def eprint(*args, **kwargs):
    print(*args, file=sys.stderr, **kwargs)


def parse_kv_list(items: Optional[List[str]]) -> Dict[str, str]:
    out: Dict[str, str] = {}
    if not items:
        return out
    for item in items:
        if "=" not in item:
            raise ValueError(f"Invalid key=value item: {item}")
        k, v = item.split("=", 1)
        k = k.strip()
        v = v.strip()
        if not k:
            raise ValueError(f"Invalid empty key in item: {item}")
        out[k] = v
    return out


def parse_topics_list(topics: Optional[List[str]]) -> List[str]:
    if not topics:
        return []
    out: List[str] = []
    for t in topics:
        if not t:
            continue
        parts = [p.strip() for p in t.split(",") if p.strip()]
        out.extend(parts)
    seen = set()
    uniq = []
    for t in out:
        if t not in seen:
            seen.add(t)
            uniq.append(t)
    return uniq


def parse_topics_json(json_str: Optional[str]) -> List[dict]:
    if not json_str:
        return []
    try:
        data = json.loads(json_str)
    except json.JSONDecodeError as e:
        raise ValueError(f"Invalid JSON for --topics-json: {e}") from e
    if not isinstance(data, list):
        raise ValueError("--topics-json must be a JSON array")
    for i, item in enumerate(data):
        if not isinstance(item, dict):
            raise ValueError(f"--topics-json[{i}] must be an object")
        if "name" not in item or not isinstance(item["name"], str) or not item["name"].strip():
            raise ValueError(f"--topics-json[{i}].name is required and must be a non-empty string")
    return data


def build_admin(args) -> KafkaAdminClient:
    security_protocol = args.security_protocol
    sasl_mechanism = args.sasl_mechanism
    sasl_plain_username = args.sasl_username
    sasl_plain_password = args.sasl_password

    kwargs = {
        "bootstrap_servers": args.bootstrap_servers,
        "client_id": args.client_id,
        "request_timeout_ms": args.request_timeout_ms,
        "api_version_auto_timeout_ms": args.api_version_auto_timeout_ms,
    }

    if security_protocol:
        kwargs["security_protocol"] = security_protocol
    if sasl_mechanism:
        kwargs["sasl_mechanism"] = sasl_mechanism
    if sasl_plain_username is not None:
        kwargs["sasl_plain_username"] = sasl_plain_username
    if sasl_plain_password is not None:
        kwargs["sasl_plain_password"] = sasl_plain_password

    if args.ssl_cafile:
        kwargs["ssl_cafile"] = args.ssl_cafile
    if args.ssl_certfile:
        kwargs["ssl_certfile"] = args.ssl_certfile
    if args.ssl_keyfile:
        kwargs["ssl_keyfile"] = args.ssl_keyfile
    if args.ssl_password:
        kwargs["ssl_password"] = args.ssl_password
    if args.ssl_check_hostname is not None:
        kwargs["ssl_check_hostname"] = args.ssl_check_hostname

    return KafkaAdminClient(**kwargs)


def wait_for_topics(admin: KafkaAdminClient, topics: List[str], timeout_s: int = 30, interval_s: float = 0.5) -> bool:
    deadline = time.time() + timeout_s
    remaining = set(topics)
    while remaining and time.time() < deadline:
        try:
            existing = set(admin.list_topics())
        except KafkaError:
            time.sleep(interval_s)
            continue
        remaining = remaining - existing
        if remaining:
            time.sleep(interval_s)
    return not remaining


def cmd_create_topics(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics_list(args.topics)
    topics_json = parse_topics_json(args.topics_json)

    if not topics and not topics_json:
        eprint("No topics provided. Use --topics or --topics-json.")
        return 2

    default_configs = parse_kv_list(args.config)
    new_topics: List[NewTopic] = []

    for name in topics:
        new_topics.append(
            NewTopic(
                name=name,
                num_partitions=args.partitions,
                replication_factor=args.replication_factor,
                topic_configs=default_configs if default_configs else None,
            )
        )

    for item in topics_json:
        name = item["name"].strip()
        partitions = int(item.get("partitions", args.partitions))
        replication_factor = int(item.get("replication_factor", args.replication_factor))
        cfg = dict(default_configs)
        item_cfg = item.get("config", {})
        if item_cfg is None:
            item_cfg = {}
        if not isinstance(item_cfg, dict):
            raise ValueError(f"Invalid config for topic {name}: must be an object")
        for k, v in item_cfg.items():
            cfg[str(k)] = str(v)
        new_topics.append(
            NewTopic(
                name=name,
                num_partitions=partitions,
                replication_factor=replication_factor,
                topic_configs=cfg if cfg else None,
            )
        )

    if not new_topics:
        eprint("No topics to create.")
        return 2

    try:
        admin.create_topics(new_topics=new_topics, validate_only=args.validate_only, timeout_ms=args.timeout_ms)
    except TopicAlreadyExistsError as e:
        if args.if_not_exists:
            return 0
        eprint(f"Topic already exists: {e}")
        return 1
    except KafkaError as e:
        eprint(f"Failed to create topics: {e}")
        return 1

    if args.wait:
        names = [t.name for t in new_topics]
        ok = wait_for_topics(admin, names, timeout_s=args.wait_timeout_s)
        if not ok:
            eprint(f"Timed out waiting for topics to appear: {', '.join(names)}")
            return 1
    return 0


def cmd_increase_partitions(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics_list(args.topics)
    if not topics:
        eprint("No topics provided. Use --topics.")
        return 2
    if args.total_partitions is None and args.add_partitions is None:
        eprint("Provide either --total-partitions or --add-partitions.")
        return 2
    if args.total_partitions is not None and args.add_partitions is not None:
        eprint("Provide only one of --total-partitions or --add-partitions.")
        return 2

    try:
        current = admin.describe_topics(topics)
    except UnknownTopicOrPartitionError as e:
        eprint(f"Unknown topic: {e}")
        return 1
    except KafkaError as e:
        eprint(f"Failed to describe topics: {e}")
        return 1

    current_partitions: Dict[str, int] = {}
    for td in current:
        name = td.get("topic")
        parts = td.get("partitions", [])
        current_partitions[name] = len(parts)

    topic_partitions: Dict[str, int] = {}
    for t in topics:
        cur = current_partitions.get(t)
        if cur is None:
            eprint(f"Topic not found in describe response: {t}")
            return 1
        if args.total_partitions is not None:
            target = int(args.total_partitions)
        else:
            target = cur + int(args.add_partitions)
        if target < cur:
            eprint(f"Cannot decrease partitions for {t}: current={cur}, target={target}")
            return 2
        if target == cur:
            if args.skip_if_noop:
                continue
            eprint(f"No-op for {t}: already has {cur} partitions")
            continue
        topic_partitions[t] = target

    if not topic_partitions:
        return 0

    try:
        admin.create_partitions(topic_partitions=topic_partitions, timeout_ms=args.timeout_ms, validate_only=args.validate_only)
    except KafkaError as e:
        eprint(f"Failed to increase partitions: {e}")
        return 1
    return 0


def cmd_alter_configs(admin: KafkaAdminClient, args) -> int:
    topics = parse_topics_list(args.topics)
    if not topics:
        eprint("No topics provided. Use --topics.")
        return 2

    set_cfg = parse_kv_list(args.set)
    del_keys = args.delete or []

    if not set_cfg and not del_keys:
        eprint("No config changes provided. Use --set key=value and/or --delete key.")
        return 2

    resources = [("topic", t) for t in topics]

    # kafka-python AdminClient supports alter_configs(config_resources)
    # config_resources: dict of (resource_type, resource_name) -> dict of configs
    # Deletions are represented by setting value to None in some brokers; kafka-python passes through.
    config_resources: Dict[Tuple[str, str], Dict[str, Optional[str]]] = {}
    for r in resources:
        cfg: Dict[str, Optional[str]] = {}
        for k, v in set_cfg.items():
            cfg[k] = v
        for k in del_keys:
            cfg[k] = None
        config_resources[r] = cfg

    try:
        admin.alter_configs(config_resources=config_resources, timeout_ms=args.timeout_ms, validate_only=args.validate_only)
    except KafkaError as e:
        eprint(f"Failed to alter configs: {e}")
        return 1
    return 0


